async function fileToBase64(file) {
  if (!file || !(file instanceof File)) return null;
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = () => resolve({ name: file.name, type: file.type, data: reader.result });
    reader.onerror = () => resolve(null);
    reader.readAsDataURL(file);
  });
}

async function serializeData(obj) {
  if (!obj || typeof obj !== "object") return obj;
  const result = {};
  for (const [key, val] of Object.entries(obj)) {
    if (val instanceof File) {
      result[key] = await fileToBase64(val);
    } else if (Array.isArray(val)) {
      result[key] = await Promise.all(val.map(v => v instanceof File ? fileToBase64(v) : serializeData(v)));
    } else if (val && typeof val === "object" && !(val instanceof Date)) {
      result[key] = await serializeData(val);
    } else {
      result[key] = val;
    }
  }
  return result;
}

async function supabaseSave(table, data) {
  try {
    const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=email`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey": SUPABASE_KEY,
        "Authorization": `Bearer ${SUPABASE_KEY}`,
        "Prefer": "return=representation,resolution=merge-duplicates",
        "on_conflict": "email",
      },
      body: JSON.stringify(data),
    });
    if (!res.ok) {
      const err = await res.text();
      console.error("Supabase save error:", err);
      return null;
    }
    return await res.json();
  } catch (e) {
    console.error("Supabase error:", e);
    return null;
  }
}

