function StepEnterEmail({ onNewUser, onExistingUser, prefillEmail }) {
  const [email, setEmail] = useState(prefillEmail || "");
  const [err, setErr] = useState("");
  const [loading, setLoading] = useState(false);
  const isValid = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email.trim());
  const handleContinue = () => {
    if (!isValid) {
      setErr("Please enter a valid email address.");
      return;
    }
    setLoading(true);
    setErr("");
    setTimeout(() => {
      const accounts = getAccounts();
      const norm = email.trim().toLowerCase();
      if (accounts[norm]) {
        onExistingUser(norm);
      } else {
        const token = generateToken();
        const pending = getPending();
        pending[norm] = { token, created: Date.now() };
        savePending(pending);
        onNewUser(norm, token);
      }
      setLoading(false);
    }, 600);
  };
  return (
    <>
      <div style={{ marginBottom: 26 }}>
        <div
          style={{
            fontSize: 22,
            fontWeight: 700,
            color: AC.text,
            marginBottom: 5,
          }}
        >
          Get started
        </div>
        <div style={{ fontSize: 14, color: AC.textFaint, lineHeight: 1.6 }}>
          Enter your email address to create an account and begin your
          application.
        </div>
      </div>
      <AuthAlert msg={err} />
      <div style={{ marginBottom: 16 }}>
        <div
          style={{
            fontSize: 13,
            color: AC.textMid,
            fontWeight: 500,
            marginBottom: 6,
          }}
        >
          Email Address
        </div>
        <AuthInput
          type="email"
          placeholder="you@example.com"
          value={email}
          onChange={(e) => {
            setEmail(e.target.value);
            setErr("");
          }}
        />
      </div>
      <AuthBtn primary disabled={!isValid || loading} onClick={handleContinue}>
        {loading ? "Checking..." : "Continue"}
      </AuthBtn>
      <div style={{ marginTop: 18, textAlign: "center" }}>
        <span style={{ fontSize: 13, color: AC.textFaint }}>
          Already have an account?{" "}
        </span>
        <button
          onClick={() => onExistingUser(null)}
          style={{
            fontSize: 13,
            color: AC.blue,
            fontWeight: 500,
            background: "none",
            border: "none",
            cursor: "pointer",
            fontFamily: "'Inter',sans-serif",
            padding: 0,
            borderBottom: "1px solid rgba(42,90,138,0.4)",
            lineHeight: 1.4,
          }}
        >
          Log in
        </button>
      </div>
    </>
  );
}

