// ── MULTI-FILE UPLOAD BOX ──
function MultiUploadBox({
  label,
  hint,
  onFiles,
  files = [],
  accept,
  disabled,
}) {
  const ref = useRef();
  const handleChange = (e) => {
    const newFiles = Array.from(e.target.files);
    if (newFiles.length > 0) onFiles([...files, ...newFiles]);
    e.target.value = "";
  };
  const removeFile = (idx) => {
    const arr = files.filter((_, i) => i !== idx);
    onFiles(arr);
  };
  const hasFiles = files.length > 0;
  return (
    <div>
      <div
        onClick={() => !disabled && ref.current.click()}
        style={{
          border: `2px dashed ${hasFiles ? C.green : C.border}`,
          borderRadius: 8,
          padding: "14px 16px",
          textAlign: "center",
          cursor: disabled ? "not-allowed" : "pointer",
          background: hasFiles ? C.greenBg : C.bgPanel,
          transition: "all 0.15s",
        }}
        onMouseEnter={(e) => {
          if (!disabled && !hasFiles)
            e.currentTarget.style.borderColor = C.textFaint;
        }}
        onMouseLeave={(e) => {
          if (!disabled && !hasFiles)
            e.currentTarget.style.borderColor = C.border;
        }}
      >
        <input
          ref={ref}
          type="file"
          accept={accept || "*"}
          multiple
          style={{ display: "none" }}
          onChange={handleChange}
        />
        <div style={{ fontSize: 20, marginBottom: 4 }}>
          {hasFiles ? "📎" : "📎"}
        </div>
        <div
          style={{
            fontSize: 13,
            color: hasFiles ? C.green : C.text,
            fontFamily: "'Inter',sans-serif",
            fontWeight: 600,
          }}
        >
          {hasFiles
            ? `${files.length} file${files.length > 1 ? "s" : ""} uploaded`
            : label}
        </div>
        {hint && !hasFiles && (
          <div
            style={{
              fontSize: 11,
              color: C.textFaint,
              fontFamily: "'Inter',sans-serif",
              marginTop: 2,
              fontStyle: "italic",
            }}
          >
            {hint}
          </div>
        )}
        {hasFiles && (
          <div
            style={{
              fontSize: 11,
              color: C.green,
              fontFamily: "'Inter',sans-serif",
              marginTop: 2,
            }}
          >
            Click to add more files
          </div>
        )}
      </div>
      {hasFiles && (
        <div
          style={{
            marginTop: 6,
            display: "flex",
            flexDirection: "column",
            gap: 4,
          }}
        >
          {files.map((f, i) => (
            <div
              key={i}
              style={{
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                background: C.bgPanel,
                border: `1px solid ${C.border}`,
                borderRadius: 5,
                padding: "5px 10px",
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <span style={{ fontSize: 13 }}>📄</span>
                <span
                  style={{
                    fontSize: 12,
                    color: C.text,
                    fontFamily: "'Inter',sans-serif",
                    maxWidth: 200,
                    overflow: "hidden",
                    textOverflow: "ellipsis",
                    whiteSpace: "nowrap",
                  }}
                >
                  {f.name}
                </span>
              </div>
              {!disabled && (
                <button
                  onClick={() => removeFile(i)}
                  style={{
                    fontSize: 11,
                    color: C.red,
                    background: "none",
                    border: "none",
                    cursor: "pointer",
                    fontFamily: "'Inter',sans-serif",
                    padding: "0 4px",
                  }}
                >
                  ✕
                </button>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

