function StageIndicator({ stage, stages, stagesDone, onClickStage }) {
  return (
    <div
      style={{
        display: "flex",
        alignItems: "flex-start",
        gap: 0,
        justifyContent: "center",
        marginBottom: 6,
      }}
    >
      {stages.map((s, i) => {
        const done = stagesDone[i];
        const active = i === stage;
        const canAccess = done || i === 0 || stagesDone[i - 1];
        return (
          <div key={i} style={{ display: "flex", alignItems: "center" }}>
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 5,
                cursor: canAccess && !active ? "pointer" : "default",
              }}
              onClick={() => canAccess && !active && onClickStage(i)}
            >
              <div
                style={{
                  width: 38,
                  height: 38,
                  borderRadius: "50%",
                  background: done ? C.green : active ? C.text : C.bgPanel,
                  border: `2px solid ${
                    done ? C.green : active ? C.text : C.border
                  }`,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: done ? 14 : 13,
                  color: done || active ? "#FAF8F4" : C.textFaint,
                  fontFamily: "'Inter',sans-serif",
                  fontWeight: 700,
                  transition: "all 0.2s",
                }}
              >
                {done ? "✓" : i + 1}
              </div>
              <div
                className="flyck-stepper-label"
                style={{
                  fontSize: 9,
                  color: done ? C.green : active ? C.text : C.textFaint,
                  fontFamily: "'Inter',sans-serif",
                  letterSpacing: "0.05em",
                  whiteSpace: "nowrap",
                  fontWeight: done || active ? 600 : 400,
                }}
              >
                {s}
              </div>
            </div>
            {i < stages.length - 1 && (
              <div
                className="flyck-stepper-conn"
                style={{
                  width: 52,
                  height: 2,
                  background: done ? C.green : C.border,
                  margin: "0 4px",
                  marginBottom: 18,
                  transition: "all 0.3s",
                }}
              />
            )}
          </div>
        );
      })}
    </div>
  );
}

// ── HMRC PDF READER (improved prompt for better parsing) ──
async function readHMRCPdf(file) {
  const base64 = await new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result.split(",")[1]);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });

  const response = await fetch("/api/claude", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 2000,
      messages: [
        {
          role: "user",
          content: [
            {
              type: "document",
              source: {
                type: "base64",
                media_type: "application/pdf",
                data: base64,
              },
            },
            {
              type: "text",
              text: `You are a UK employment history parser. This document may be an HMRC PAYE record, P60, P45, payslips, or similar. Extract ALL employment records.

IMPORTANT: Even if the document is hard to read, do your best. Look for employer names, dates, tax references, income amounts. If you see any names of companies or organisations with associated dates or years, include them.

Return ONLY valid JSON, no markdown, no explanation:
{
  "employments": [
    {
      "employer": "Employer name as shown",
      "startDate": "YYYY-MM-DD",
      "endDate": "YYYY-MM-DD or null if current",
      "hmrcRef": "PAYE ref if visible, else null",
      "isDWP": false
    }
  ]
}

Rules:
- isDWP = true for: DWP, Job Centre, JSA, ESA, Universal Credit, PIP, Income Support, Housing Benefit, Tax Credits, any UK benefits
- For tax years like "2019-20": startDate = "2019-04-06", endDate = "2020-04-05"  
- Sort oldest first
- If only a year is visible (e.g. 2021), use April 6 as start
- Always return JSON even if very few records found
- If document appears blank or unreadable, still return {"employments": []} `,
            },
          ],
        },
      ],
    }),
  });

  if (!response.ok) {
    const errText = await response.text();
    throw new Error(`API error ${response.status}: ${errText}`);
  }
  const data = await response.json();
  if (data.error)
    throw new Error(
      `Claude API: ${data.error.message || JSON.stringify(data.error)}`
    );

  const text = (data.content || [])
    .map((b) => b.text || "")
    .join("")
    .trim();
  if (!text) throw new Error("No response from API. Please try again.");

  let parsed;
  try {
    const clean = text
      .replace(/^```[\w]*\n?/gm, "")
      .replace(/```$/gm, "")
      .trim();
    const jsonMatch = clean.match(/\{[\s\S]*\}/);
    if (!jsonMatch) throw new Error("No JSON found");
    parsed = JSON.parse(jsonMatch[0]);
  } catch {
    throw new Error(
      "Could not read employment data from this document. Please ensure you have uploaded a valid HMRC PAYE history PDF."
    );
  }

  if (!parsed.employments || !Array.isArray(parsed.employments))
    throw new Error("Invalid document format returned.");

  const employments = parsed.employments || [];
  const gaps = [];
  for (let i = 0; i < employments.length - 1; i++) {
    const endA = new Date(employments[i].endDate || new Date());
    const startB = new Date(employments[i + 1].startDate);
    const days = Math.floor((startB - endA) / (1000 * 60 * 60 * 24));
    if (days > 0)
      gaps.push({
        from: employments[i].endDate,
        to: employments[i + 1].startDate,
        days,
        afterEmployer: employments[i].employer,
        beforeEmployer: employments[i + 1].employer,
        isDWPRelated: employments[i].isDWP || employments[i + 1].isDWP,
      });
  }
  const dwpEntries = employments.filter((e) => e.isDWP);
  return { employments, gaps, dwpEntries };
}

const fmtDate = (d) =>
  d
    ? new Date(d).toLocaleDateString("en-GB", {
        day: "numeric",
        month: "short",
        year: "numeric",
      })
    : "Present";

