// ASK FLYCK WIDGET
// ══════════════════════════════════════════
function AskFlyck() {
  const [open, setOpen] = useState(false);
  const [messages, setMessages] = useState([
    {
      role: "bot",
      text: "Hi! I'm Flyck, your registration assistant. Ask me about ID documents, HMRC, employment gaps, DBS checks, GDPR, or anything about this process.",
    },
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const QUICK = [
    "What ID do I need?",
    "How do I upload my work history?",
    "I have a gap in my employment",
    "What is a DBS check?",
  ];
  const endRef = useRef();
  const send = async (text) => {
    if (!text.trim()) return;
    setInput("");
    setMessages((m) => [...m, { role: "user", text: text.trim() }]);
    setLoading(true);
    try {
      const res = await fetch("/api/claude", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-6",
          max_tokens: 1000,
          system:
            "You are Flyck, a friendly and knowledgeable compliance assistant on the Flyck.ai candidate registration portal. Help candidates complete their registration across 4 stages: (1) Personal profile with health questionnaire and GDPR consents — includes a question about whether they hold a full UK driving licence which determines if DVLA checks appear, (2) ID verification (multi-file upload now supported for each document — passport, driving licence if applicable, birth cert, proof of address etc — bank-grade Onfido checks), (3) Work History — starts with a Reference Consent form for The Lanes Group that must be signed before uploading HMRC history; employment history is auto-parsed for gaps — gaps over 28 days need a personal reference known for 3+ years plus evidence of UK presence; school references and self-employment references are also supported; DWP periods require bank statements; a downloadable HMRC guide is available, (4) DBS check (Basic, Standard, Enhanced, or Enhanced+Barred — self-disclosure of convictions required). Be warm, concise and reassuring. Give practical step-by-step guidance. Mention CAP 2330 compliance where relevant for aviation roles.",
          messages: [
            ...messages
              .filter((_, i) => i > 0)
              .map((m) => ({
                role: m.role === "bot" ? "assistant" : "user",
                content: m.text,
              })),
            { role: "user", content: text.trim() },
          ],
        }),
      });
      const d = await res.json();
      setMessages((m) => [
        ...m,
        {
          role: "bot",
          text: d.content?.[0]?.text || "Sorry, I couldn't respond right now.",
        },
      ]);
    } catch {
      setMessages((m) => [
        ...m,
        {
          role: "bot",
          text: "Sorry, I'm having trouble connecting. Please try again.",
        },
      ]);
    }
    setLoading(false);
  };
  useEffect(() => {
    endRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, loading]);
  return (
    <>
      <button
        onClick={() => setOpen((o) => !o)}
        style={{
          position: "fixed",
          bottom: 24,
          right: 24,
          width: 56,
          height: 56,
          borderRadius: "50%",
          background: C.text,
          border: "none",
          cursor: "pointer",
          boxShadow: "0 4px 20px rgba(0,0,0,0.25)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          fontSize: 24,
          zIndex: 500,
        }}
      >
        {open ? "✕" : "🤖"}
      </button>
      {!open && (
        <div
          onClick={() => setOpen(true)}
          style={{
            position: "fixed",
            bottom: 32,
            right: 90,
            background: C.bgCard,
            border: `1px solid ${C.border}`,
            borderRadius: 20,
            padding: "6px 14px",
            cursor: "pointer",
            boxShadow: "0 2px 12px rgba(0,0,0,0.1)",
            zIndex: 499,
          }}
        >
          <span
            style={{
              fontSize: 13,
              color: C.text,
              fontFamily: "'Inter',sans-serif",
              fontWeight: 600,
            }}
          >
            Ask Flyck
          </span>
        </div>
      )}
      {open && (
        <div
          className="flyck-ask-widget"
          style={{
            position: "fixed",
            bottom: 92,
            right: 24,
            width: 380,
            height: 520,
            background: C.bgCard,
            border: `1px solid ${C.border}`,
            borderRadius: 14,
            boxShadow: "0 12px 48px rgba(0,0,0,0.18)",
            display: "flex",
            flexDirection: "column",
            zIndex: 500,
            overflow: "hidden",
          }}
        >
          <div
            style={{
              background: C.text,
              padding: "14px 18px",
              display: "flex",
              alignItems: "center",
              gap: 10,
              flexShrink: 0,
            }}
          >
            <div
              style={{
                width: 36,
                height: 36,
                borderRadius: "50%",
                background: "rgba(255,255,255,0.15)",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                fontSize: 18,
              }}
            >
              🤖
            </div>
            <div>
              <div
                style={{
                  fontSize: 15,
                  fontWeight: 700,
                  color: "#FAF8F4",
                  fontFamily: "'Inter',sans-serif",
                }}
              >
                Ask Flyck
              </div>
              <div
                style={{
                  fontSize: 11,
                  color: "rgba(250,248,244,0.6)",
                  fontFamily: "'Inter',sans-serif",
                }}
              >
                Registration Assistant
              </div>
            </div>
          </div>
          <div style={{ flex: 1, overflowY: "auto", padding: "14px 16px" }}>
            {messages.map((m, i) => (
              <div
                key={i}
                style={{
                  display: "flex",
                  justifyContent: m.role === "user" ? "flex-end" : "flex-start",
                  marginBottom: 10,
                }}
              >
                <div
                  style={{
                    maxWidth: "82%",
                    padding: "10px 14px",
                    borderRadius:
                      m.role === "user"
                        ? "12px 12px 3px 12px"
                        : "12px 12px 12px 3px",
                    background: m.role === "user" ? C.text : C.bgPanel,
                    border:
                      m.role === "user" ? "none" : `1px solid ${C.border}`,
                  }}
                >
                  <div
                    style={{
                      fontSize: 14,
                      color: m.role === "user" ? "#FAF8F4" : C.text,
                      fontFamily: "'Inter',sans-serif",
                      lineHeight: 1.55,
                      whiteSpace: "pre-wrap",
                    }}
                  >
                    {m.text}
                  </div>
                </div>
              </div>
            ))}
            {loading && (
              <div
                style={{
                  display: "flex",
                  justifyContent: "flex-start",
                  marginBottom: 10,
                }}
              >
                <div
                  style={{
                    padding: "10px 16px",
                    borderRadius: "12px 12px 12px 3px",
                    background: C.bgPanel,
                    border: `1px solid ${C.border}`,
                  }}
                >
                  <div style={{ display: "flex", gap: 4 }}>
                    {[0, 1, 2].map((i) => (
                      <div
                        key={i}
                        style={{
                          width: 6,
                          height: 6,
                          borderRadius: "50%",
                          background: C.textFaint,
                        }}
                      />
                    ))}
                  </div>
                </div>
              </div>
            )}
            <div ref={endRef} />
          </div>
          {messages.length <= 2 && (
            <div
              style={{
                padding: "0 12px 8px",
                display: "flex",
                flexWrap: "wrap",
                gap: 5,
                flexShrink: 0,
              }}
            >
              {QUICK.map((q) => (
                <button
                  key={q}
                  onClick={() => send(q)}
                  style={{
                    fontSize: 12,
                    color: C.blue,
                    background: C.blueBg,
                    border: `1px solid ${C.blue}30`,
                    borderRadius: 20,
                    padding: "4px 10px",
                    cursor: "pointer",
                    fontFamily: "'Inter',sans-serif",
                  }}
                >
                  {q}
                </button>
              ))}
            </div>
          )}
          <div
            style={{
              padding: "10px 12px",
              borderTop: `1px solid ${C.border}`,
              display: "flex",
              gap: 8,
              flexShrink: 0,
            }}
          >
            <input
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === "Enter" && !loading && send(input)}
              placeholder="Ask anything…"
              style={{
                flex: 1,
                background: C.bgInput,
                border: `1px solid ${C.border}`,
                borderRadius: 8,
                padding: "8px 12px",
                fontSize: 14,
                fontFamily: "'Inter',sans-serif",
                color: C.text,
                outline: "none",
              }}
            />
            <button
              onClick={() => send(input)}
              disabled={loading || !input.trim()}
              style={{
                width: 36,
                height: 36,
                borderRadius: 8,
                background: C.text,
                border: "none",
                cursor: loading || !input.trim() ? "not-allowed" : "pointer",
                color: "#FAF8F4",
                fontSize: 16,
                opacity: loading || !input.trim() ? 0.4 : 1,
              }}
            >
              →
            </button>
          </div>
        </div>
      )}
    </>
  );
}

// ══════════════════════════════════════════
// ROOT
// ══════════════════════════════════════════
function FlyckyPortal() {
  const STAGE_LABELS = [
    "PROFILE",
    "ID CHECK",
    "WORK HISTORY",
    "DBS CHECK",
    "COMPLETED",
  ];
  const [stage, setStage] = useState(0);
  const [done, setDone] = useState([false, false, false, false, false]);
  const [p1, setP1] = useState({});
  const [p2, setP2] = useState({});
  const [p3, setP3] = useState({});
  const [p4, setP4] = useState({});
  const markDone = (i) => {
    const d = [...done];
    d[i] = true;
    setDone(d);
  };
  const goNext = async () => {
    markDone(stage);
    window.scrollTo({ top: 0, behavior: "smooth" });
    document.querySelector(".flyck-content")?.scrollTo({ top: 0, behavior: "smooth" });
    // Save to Supabase at every stage so candidate appears in client portal immediately
    const allData = { ...p1, ...p2, ...p3, ...p4 };
    const statusMap = ["Profile Started", "ID Submitted", "Work History Submitted", "DBS Submitted", "Fully Submitted"];
    await supabaseSave("candidates", {
      email: allData.email || "",
      first_name: allData.firstName || "",
      last_name: allData.lastName || "",
      dob: allData.dob || null,
      nationality: allData.nationality || "",
      phone: allData.phone || "",
      ni_number: allData.ni || "",
      role: allData.role || "",
      address: allData.address || "",
      city: allData.city || "",
      postcode: allData.postcode || "",
      notice_period: allData.noticePeriod || "",
      dbs_type: allData.dbsType || "",
      status: statusMap[stage] || "In Progress",
      submitted_at: new Date().toISOString(),
      raw_data: JSON.stringify(await serializeData(allData)),
    });
    setStage((s) => Math.min(s + 1, 4));
  };
  const allData = { ...p1, ...p2, ...p3, ...p4 };
  const isCompleted = stage === 4;
  return (
    <div style={{ minHeight: "100vh", background: C.bg }}><NotificationBell portalTarget="agency" />
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=DM+Serif+Display:ital@0;1&family=Inter:wght@300;400;500;600;700&display=swap');
        *{box-sizing:border-box;margin:0;padding:0;}
        html{-webkit-text-size-adjust:100%;}
        ::-webkit-scrollbar{width:4px;height:4px;}
        ::-webkit-scrollbar-thumb{background:#D4C9B0;border-radius:4px;}
        select option{background:#fff;color:#1A1208;}
        input::placeholder,textarea::placeholder{color:#9A8F7E;}
        button{transition:all 0.12s;}
        button:hover:not(:disabled){opacity:0.84;}
        @keyframes pulse{0%,100%{opacity:0.3;}50%{opacity:1;}}
        @media(max-width:700px){
          .flyck-layout{flex-direction:column!important;}
          .flyck-sidebar{width:100%!important;height:auto!important;position:relative!important;flex-direction:row!important;align-items:center!important;border-right:none!important;border-bottom:1px solid #E2DDD5!important;flex-shrink:0!important;}
          .flyck-sidebar-logo{padding:12px 16px!important;border-bottom:none!important;border-right:1px solid #E2DDD5!important;flex-shrink:0;}
          .flyck-sidebar-logo .logo-text{font-size:26px!important;}
          .flyck-sidebar-nav{display:none!important;}
          .flyck-sidebar-progress{display:none!important;}
          .flyck-sidebar-user{padding:10px 14px!important;border-top:none!important;border-left:1px solid #E2DDD5!important;margin-left:auto!important;}
          .flyck-topbar{padding:12px 16px!important;}
          .flyck-topbar-title{font-size:16px!important;}
          .flyck-topbar-sub{display:none!important;}
          .flyck-secure-badge{display:none!important;}
          .flyck-stepper-wrap{padding:12px 16px 10px!important;}
          .flyck-stepper-label{display:none!important;}
          .flyck-stepper-conn{width:20px!important;}
          .flyck-content{padding:16px 14px 100px!important;}
          .flyck-card{padding:16px 14px!important;}
          .g2{grid-template-columns:1fr!important;}
          .g3{grid-template-columns:1fr!important;}
          .g4{grid-template-columns:1fr 1fr!important;}
          .g-stage5{grid-template-columns:1fr!important;}
          .flyck-ask-widget{width:calc(100vw - 32px)!important;right:16px!important;}
          select,input,textarea{font-size:16px!important;-webkit-appearance:none;}
          .flyck-btn-row{flex-direction:column!important;}
          .flyck-btn-row>button{width:100%!important;}
          .sig-canvas{height:110px!important;}
        }
      `}</style>
      <div
        style={{ display: "flex", minHeight: "100vh" }}
        className="flyck-layout"
      >
        {/* SIDEBAR */}
        <div
          className="flyck-sidebar"
          style={{
            width: 215,
            background: C.bgPanel,
            borderRight: `1px solid ${C.border}`,
            display: "flex",
            flexDirection: "column",
            flexShrink: 0,
            position: "sticky",
            top: 0,
            height: "100vh",
          }}
        >
          <div
            className="flyck-sidebar-logo"
            style={{
              padding: "24px 18px 20px",
              borderBottom: `1px solid ${C.border}`,
            }}
          >
            <div
              className="logo-text"
              style={{
                fontSize: 38,
                fontWeight: 700,
                color: C.text,
                fontFamily: "'DM Serif Display',serif",
                letterSpacing: "-0.02em",
                lineHeight: 1,
              }}
            >
              Flyck<span style={{ fontStyle: "italic" }}>.ai</span>
            </div>
            <div
              style={{
                fontSize: 10,
                color: C.textFaint,
                fontFamily: "'Inter',sans-serif",
                marginTop: 6,
                letterSpacing: "0.07em",
              }}
            >
              CANDIDATE PORTAL
            </div>
          </div>
          <nav
            className="flyck-sidebar-nav"
            style={{ flex: 1, padding: "14px 8px" }}
          >
            <div
              style={{
                fontSize: 10,
                color: C.textFaint,
                fontFamily: "'Inter',sans-serif",
                letterSpacing: "0.07em",
                padding: "4px 12px 10px",
              }}
            >
              REGISTRATION STAGES
            </div>
            {STAGE_LABELS.map((label, i) => {
              const isDone = done[i];
              const isActive = i === stage;
              const isLast = i === 4;
              return (
                <button
                  key={i}
                  onClick={() => setStage(i)}
                  style={{
                    width: "100%",
                    padding: "9px 12px",
                    background: isActive ? "#fff" : "transparent",
                    border: `1px solid ${isActive ? C.border : "transparent"}`,
                    borderRadius: 6,
                    cursor: "pointer",
                    color: isDone
                      ? C.green
                      : isActive
                      ? C.text
                      : isLast
                      ? C.textFaint
                      : C.textMid,
                    fontSize: 14,
                    fontFamily: "'Inter',sans-serif",
                    fontWeight: isActive ? 600 : 400,
                    textAlign: "left",
                    marginBottom: 2,
                    display: "flex",
                    alignItems: "center",
                    gap: 8,
                  }}
                >
                  <span
                    style={{
                      fontFamily: "'Inter',sans-serif",
                      fontSize: 12,
                      color: isDone ? C.green : isActive ? C.text : C.textFaint,
                    }}
                  >
                    {isDone ? "✓" : i + 1 + "."}
                  </span>
                  {label}
                </button>
              );
            })}
          </nav>
          <div
            className="flyck-sidebar-progress"
            style={{ padding: "12px 18px", borderTop: `1px solid ${C.border}` }}
          >
            <div
              style={{
                fontSize: 10,
                color: C.textFaint,
                fontFamily: "'Inter',sans-serif",
                marginBottom: 8,
                letterSpacing: "0.05em",
              }}
            >
              OVERALL PROGRESS
            </div>
            <div
              style={{
                width: "100%",
                height: 4,
                background: C.border,
                borderRadius: 2,
                overflow: "hidden",
                marginBottom: 6,
              }}
            >
              <div
                style={{
                  height: "100%",
                  width: `${isCompleted ? 100 : (stage / 4) * 100}%`,
                  background: isCompleted ? C.green : C.text,
                  borderRadius: 2,
                  transition: "width 0.4s ease",
                }}
              />
            </div>
            <div
              style={{
                fontSize: 11,
                color: isCompleted ? C.green : C.textMid,
                fontFamily: "'Inter',sans-serif",
              }}
            >
              {isCompleted ? "Complete ✓" : `Step ${stage + 1} of 5`}
            </div>
          </div>
          <div
            className="flyck-sidebar-user"
            style={{
              padding: "10px 16px 16px",
              borderTop: `1px solid ${C.border}`,
            }}
          >
            <div
              style={{
                fontSize: 14,
                color: C.text,
                fontFamily: "'Inter',sans-serif",
                fontWeight: 600,
              }}
            >
              {p1.firstName
                ? `${p1.firstName} ${p1.lastName || ""}`.trim()
                : "New Candidate"}
            </div>
            <div
              style={{
                fontSize: 10,
                color: C.textFaint,
                fontFamily: "'Inter',sans-serif",
              }}
            >
              {p1.role || "Pre-employment Screening"}
            </div>
          </div>
        </div>

        {/* MAIN */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column" }}>
          <div
            className="flyck-topbar"
            style={{
              background: C.bgCard,
              borderBottom: `1px solid ${C.border}`,
              padding: "14px 28px",
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              flexShrink: 0,
              position: "sticky",
              top: 0,
              zIndex: 10,
            }}
          >
            <div>
              <div
                className="flyck-topbar-title"
                style={{
                  fontSize: 20,
                  fontWeight: 700,
                  color: C.text,
                  fontFamily: "'Inter',sans-serif",
                }}
              >
                {isCompleted
                  ? "Registration Complete"
                  : [
                      "Personal Profile",
                      "Identity Verification",
                      "Work History",
                      "DBS Check",
                    ][stage] +
                    " — Step " +
                    (stage + 1) +
                    " of 5"}
              </div>
              <div
                className="flyck-topbar-sub"
                style={{
                  fontSize: 13,
                  color: C.textFaint,
                  fontFamily: "'Inter',sans-serif",
                  fontStyle: "italic",
                }}
              >
                {isCompleted
                  ? "Your application has been submitted · Client has been notified"
                  : "CAP 2330 Pre-Employment Compliance · Flyck.ai"}
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
              {!isCompleted && (
                <div
                  className="flyck-secure-badge"
                  style={{ display: "flex", alignItems: "center", gap: 6 }}
                >
                  <div
                    style={{
                      width: 6,
                      height: 6,
                      borderRadius: "50%",
                      background: C.green,
                    }}
                  />
                  <span
                    style={{
                      fontSize: 11,
                      color: C.green,
                      fontFamily: "'Inter',sans-serif",
                    }}
                  >
                    Secure Session
                  </span>
                </div>
              )}
              {isCompleted && (
                <Badge label="All Stages Complete ✓" color={C.green} />
              )}
            </div>
          </div>
          {!isCompleted && (
            <div
              className="flyck-stepper-wrap"
              style={{
                background: C.bgCard,
                borderBottom: `1px solid ${C.border}`,
                padding: "18px 28px 14px",
              }}
            >
              <StageIndicator
                stage={stage}
                stages={STAGE_LABELS.slice(0, 4)}
                stagesDone={done.slice(0, 4)}
                onClickStage={(i) => setStage(i)}
              />
            </div>
          )}
          <div
            className="flyck-content"
            style={{ flex: 1, overflowY: "auto", padding: "30px 28px 100px" }}
          >
            <div style={{ maxWidth: 800, margin: "0 auto" }}>
              <Card>
                {stage === 0 && (
                  <Stage1 data={p1} onChange={setP1} onNext={goNext} />
                )}
                {stage === 1 && (
                  <Stage2
                    data={p2}
                    onChange={setP2}
                    onNext={goNext}
                    onBack={() => { setStage(0); window.scrollTo({ top: 0, behavior: "smooth" }); document.querySelector(".flyck-content")?.scrollTo({ top: 0, behavior: "smooth" }); }}
                    hasUKDrivingLicence={p1.hasUKDrivingLicence}
                  />
                )}
                {stage === 2 && (
                  <Stage3
                    data={p3}
                    onChange={setP3}
                    onNext={goNext}
                    onBack={() => { setStage(1); window.scrollTo({ top: 0, behavior: "smooth" }); document.querySelector(".flyck-content")?.scrollTo({ top: 0, behavior: "smooth" }); }}
                  />
                )}
                {stage === 3 && (
                  <Stage4
                    data={p4}
                    onChange={setP4}
                    onNext={goNext}
                    onBack={() => { setStage(2); window.scrollTo({ top: 0, behavior: "smooth" }); document.querySelector(".flyck-content")?.scrollTo({ top: 0, behavior: "smooth" }); }}
                  />
                )}
                {stage === 4 && <Stage5 allData={allData} />}
              </Card>
            </div>
          </div>
        </div>
      </div>
      <AskFlyck />
    </div>
  );
}

export default function FlyckyCandidate() {
  return (
    <AuthGate>
      <FlyckyPortal />
    </AuthGate>
  );
}


